lines.forEach((line, i) => {
  try {
    const obj = JSON.parse(line);
    if (obj.type === 'message' && obj.message) {
      const msg = obj.message;
      if (msg.role === 'user') {
        // Extract text content
        let text = '';
        if (typeof msg.content === 'string') text = msg.content;
        else if (Array.isArray(msg.content)) {
          text = msg.content.filter(c => c.type === 'text').map(c => c.text).join('\n');
        }
        if (text) messages.push({ line: i, role: 'user', text: text.substring(0, 1000) });
      }
      if (msg.role === 'assistant') {
        // Extract text content (not thinking, not tool calls)
        let textParts = [];
        if (typeof msg.content === 'string') textParts.push(msg.content);
        else if (Array.isArray(msg.content)) {
          msg.content.forEach(c => {
            if (c.type === 'text') textParts.push(c.text);
          });
        }
        const text = textParts.join('\n');
        if (text && text.length > 5) messages.push({ line: i, role: 'assistant', text: text.substring(0, 1000) });
      }
    }
  } catch(e) {}
});

