"use client"

import { useCallback, useEffect } from "react"
import { Group, Panel, Separator } from "react-resizable-panels"
import type { Artifact } from "@/lib/artifact-store"
import { Button } from "@/components/ui/button"
import { X } from "@/lib/icons"
import type { CreateFormat } from "@/app/components/chat/document-editor"
import { useWorkspaceStore } from "@/lib/workspace-store"
import { WorkspaceSidebar } from "./workspace-sidebar"
import { WorkspaceMainPanel } from "./workspace-main-panel"
import { WorkspaceBottomPanel } from "./workspace-bottom-panel"
import { WorkspaceRightPanel } from "./workspace-right-panel"

type WorkspaceShellProps = {
  isOpen: boolean
  artifacts: Artifact[]
  activeArtifactId?: string
  projectId?: string | null
  chatId?: string | null
  onClose: () => void
  onCreate?: (format: CreateFormat, content: string) => void
  onRemoveArtifact: (id: string) => void
  onSelectArtifact: (id: string) => void
  onUpdateArtifact: (id: string, content: string) => void
}

export function WorkspaceShell({
  isOpen,
  artifacts,
  activeArtifactId,
  projectId,
  chatId,
  onClose,
  onCreate,
  onRemoveArtifact,
  onSelectArtifact,
  onUpdateArtifact,
}: WorkspaceShellProps) {
  const activeTab = useWorkspaceStore((state) => state.activeTab)
  const session = useWorkspaceStore((state) => state.session)
  const currentPath = useWorkspaceStore((state) => state.currentPath)
  const files = useWorkspaceStore((state) => state.files)
  const selectedFilePath = useWorkspaceStore((state) => state.selectedFilePath)
  const browserUrl = useWorkspaceStore((state) => state.browserUrl)
  const desktop = useWorkspaceStore((state) => state.desktop)
  const activities = useWorkspaceStore((state) => state.activities)
  const setContext = useWorkspaceStore((state) => state.setContext)
  const setSession = useWorkspaceStore((state) => state.setSession)
  const setFiles = useWorkspaceStore((state) => state.setFiles)
  const setCurrentPath = useWorkspaceStore((state) => state.setCurrentPath)
  const setSelectedFilePath = useWorkspaceStore((state) => state.setSelectedFilePath)
  const setBrowserUrl = useWorkspaceStore((state) => state.setBrowserUrl)
  const setDesktopState = useWorkspaceStore((state) => state.setDesktopState)
  const setActiveTab = useWorkspaceStore((state) => state.setActiveTab)
  const pushActivity = useWorkspaceStore((state) => state.pushActivity)
  const setOpen = useWorkspaceStore((state) => state.setOpen)

  const fetchJson = useCallback(async (input: RequestInfo, init?: RequestInit) => {
    const response = await fetch(input, init)
    const payload = await response.json().catch(() => ({}))
    if (!response.ok) {
      throw new Error(payload?.error || "Request failed")
    }
    return payload
  }, [])

  const initializeSession = useCallback(async () => {
    if (!isOpen) return
    try {
      const payload = await fetchJson("/api/workspace/session", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ projectId, chatId }),
      })
      setSession(payload.session)
      setCurrentPath(payload.session?.paths?.conversationRoot || null)
      pushActivity({
        kind: "success",
        title: "Workspace ready",
        detail: payload.session?.sandboxName || payload.session?.sandboxId,
      })
    } catch (error) {
      pushActivity({
        kind: "error",
        title: "Workspace failed to start",
        detail: error instanceof Error ? error.message : "Unknown error",
      })
    }
  }, [chatId, fetchJson, isOpen, projectId, pushActivity, setCurrentPath, setSession])

  const refreshFiles = useCallback(async () => {
    if (!isOpen) return
    try {
      const search = new URLSearchParams()
      if (projectId) search.set("projectId", projectId)
      if (chatId) search.set("chatId", chatId)
      if (currentPath) search.set("path", currentPath)
      const payload = await fetchJson(`/api/workspace/files?${search.toString()}`)
      if (payload.session) {
        setSession(payload.session)
      }
      setFiles(payload.files || [])
    } catch (error) {
      pushActivity({
        kind: "error",
        title: "Failed to load files",
        detail: error instanceof Error ? error.message : "Unknown error",
      })
    }
  }, [chatId, currentPath, fetchJson, isOpen, projectId, pushActivity, setFiles, setSession])

  const refreshDesktop = useCallback(async () => {
    if (!isOpen) return
    try {
      const payload = await fetchJson("/api/workspace/computer", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          projectId,
          chatId,
          action: "screenshot",
        }),
      })
      setDesktopState({
        screenshot: payload.snapshot?.screenshot || null,
        cursorPosition: payload.snapshot?.cursorPosition || null,
        status: "ready",
        error: null,
      })
    } catch (error) {
      setDesktopState({
        status: "error",
        error: error instanceof Error ? error.message : "Unknown error",
      })
    }
  }, [chatId, fetchJson, isOpen, projectId, setDesktopState])

  const startDesktop = useCallback(async () => {
    setDesktopState({ status: "starting", error: null })
    try {
      const payload = await fetchJson("/api/workspace/computer", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          projectId,
          chatId,
          action: "start",
        }),
      })
      setDesktopState({
        screenshot: payload.snapshot?.screenshot || null,
        cursorPosition: payload.snapshot?.cursorPosition || null,
        status: "ready",
        error: null,
      })
      pushActivity({
        kind: "action",
        title: "Remote desktop started",
      })
    } catch (error) {
      setDesktopState({
        status: "error",
        error: error instanceof Error ? error.message : "Unknown error",
      })
    }
  }, [chatId, fetchJson, projectId, pushActivity, setDesktopState])

  const runComputerAction = useCallback(
    async (body: Record<string, unknown>, title: string) => {
      try {
        const payload = await fetchJson("/api/workspace/computer", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            projectId,
            chatId,
            ...body,
          }),
        })
        const snapshot = payload.snapshot || payload
        setDesktopState({
          screenshot: snapshot?.screenshot || null,
          cursorPosition: snapshot?.cursorPosition || null,
          status: "ready",
          currentUrl: payload.currentUrl || desktop.currentUrl || null,
          error: null,
        })
        pushActivity({
          kind: "action",
          title,
        })
      } catch (error) {
        setDesktopState({
          status: "error",
          error: error instanceof Error ? error.message : "Unknown error",
        })
      }
    },
    [chatId, desktop.currentUrl, fetchJson, projectId, pushActivity, setDesktopState]
  )

  const openBrowser = useCallback(async () => {
    setDesktopState({ status: "starting", error: null })
    try {
      const payload = await fetchJson("/api/workspace/computer", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          projectId,
          chatId,
          action: "open_url",
          url: browserUrl,
        }),
      })
      setDesktopState({
        screenshot: payload.screenshot || null,
        cursorPosition: payload.cursorPosition || null,
        status: "ready",
        currentUrl: payload.currentUrl || browserUrl,
        error: null,
      })
      pushActivity({
        kind: "action",
        title: "Opened remote browser",
        detail: browserUrl,
      })
    } catch (error) {
      setDesktopState({
        status: "error",
        error: error instanceof Error ? error.message : "Unknown error",
      })
    }
  }, [browserUrl, chatId, fetchJson, projectId, pushActivity, setDesktopState])

  const syncDrive = useCallback(
    async (direction: "push" | "pull") => {
      try {
        const payload = await fetchJson("/api/workspace/sync", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            projectId,
            chatId,
            direction,
          }),
        })
        if (payload.session) {
          setSession(payload.session)
        }
        await refreshFiles()
        pushActivity({
          kind: "success",
          title: direction === "pull" ? "Pulled from cloud drive" : "Pushed to cloud drive",
          detail: payload.drive?.cloudFolderPath || null,
        })
      } catch (error) {
        pushActivity({
          kind: "error",
          title: "Cloud sync failed",
          detail: error instanceof Error ? error.message : "Unknown error",
        })
      }
    },
    [chatId, fetchJson, projectId, pushActivity, refreshFiles, setSession]
  )

  const uploadFolder = useCallback(
    async (filesToUpload: File[], relativePaths: string[]) => {
      try {
        const formData = new FormData()
        formData.append("projectId", projectId || "")
        formData.append("chatId", chatId || "")
        formData.append("relativePaths", JSON.stringify(relativePaths))
        filesToUpload.forEach((file) => {
          formData.append("files", file)
        })

        const payload = await fetchJson("/api/workspace/folder-upload", {
          method: "POST",
          body: formData,
        })
        if (payload.session) {
          setSession(payload.session)
        }
        setFiles(payload.files || [])
        setCurrentPath(payload.session?.paths?.conversationRoot || null)
        setActiveTab("files")
        pushActivity({
          kind: "success",
          title: "Uploaded local folder to cloud drive",
          detail: payload.drive?.cloudFolderPath || null,
        })
      } catch (error) {
        pushActivity({
          kind: "error",
          title: "Folder upload failed",
          detail: error instanceof Error ? error.message : "Unknown error",
        })
      }
    },
    [chatId, fetchJson, projectId, pushActivity, setActiveTab, setCurrentPath, setFiles, setSession]
  )

  useEffect(() => {
    setContext({ projectId, chatId })
    setOpen(isOpen)
    if (!isOpen) return
    void initializeSession()
  }, [chatId, initializeSession, isOpen, projectId, setContext, setOpen])

  useEffect(() => {
    if (!isOpen || !session) return
    void refreshFiles()
  }, [isOpen, refreshFiles, session])

  useEffect(() => {
    if (!isOpen) return
    if (activeTab !== "browser" && activeTab !== "desktop") return
    const handle = window.setInterval(() => {
      void refreshDesktop()
    }, 5000)
    return () => window.clearInterval(handle)
  }, [activeTab, isOpen, refreshDesktop])

  if (!isOpen) return null

  return (
    <div className="fixed inset-3 z-50 overflow-hidden rounded-2xl border bg-background shadow-2xl">
      <div className="flex h-14 items-center justify-between border-b px-4">
        <div>
          <div className="text-sm font-semibold">Dexter Workspace</div>
          <div className="text-muted-foreground text-xs">
            Remote folder, browser, terminal, and artifacts in one shell
          </div>
        </div>
        <Button
          type="button"
          variant="ghost"
          size="icon"
          onClick={() => {
            if (session?.drive) {
              void syncDrive("push")
            }
            onClose()
          }}
        >
          <X className="size-4" />
        </Button>
      </div>

      <div className="h-[calc(100%-3.5rem)]">
        <Group orientation="horizontal">
          <Panel defaultSize={18} minSize={14}>
            <WorkspaceSidebar
              activeTab={activeTab}
              currentPath={currentPath}
              files={files}
              drive={session?.drive}
              projectLabel={projectId || "default-project"}
              chatLabel={chatId || "default-chat"}
              onOpenTab={setActiveTab}
              onNavigateUp={() => {
                if (!currentPath) return
                const parts = currentPath.split("/").filter(Boolean)
                if (parts.length <= 1) return
                const nextPath = `/${parts.slice(0, -1).join("/")}`
                setCurrentPath(nextPath)
                setActiveTab("files")
              }}
              onRefreshFiles={() => void refreshFiles()}
              onUploadFolder={(filesToUpload, relativePaths) =>
                void uploadFolder(filesToUpload, relativePaths)
              }
              onSyncDrive={(direction) => void syncDrive(direction)}
              onSelectPath={(path, isDir) => {
                if (isDir) {
                  setCurrentPath(path)
                } else {
                  setSelectedFilePath(path)
                }
                setActiveTab("files")
              }}
            />
          </Panel>
          <Separator className="w-px bg-border" />
          <Panel defaultSize={62} minSize={42}>
            <Group orientation="vertical">
              <Panel defaultSize={72} minSize={45}>
                <WorkspaceMainPanel
                  activeTab={activeTab}
                  artifacts={artifacts}
                  activeArtifactId={activeArtifactId}
                  browserUrl={browserUrl}
                  desktopStatus={desktop.status}
                  desktopScreenshot={desktop.screenshot}
                  terminalUrl={session?.terminalUrl || null}
                  files={files}
                  selectedFilePath={selectedFilePath}
                  activities={activities}
                  session={session}
                  onBrowserUrlChange={setBrowserUrl}
                  onOpenBrowser={() => void openBrowser()}
                  onRefreshDesktop={() => void refreshDesktop()}
                  onStartDesktop={() => void startDesktop()}
                  onDesktopClick={(x, y) =>
                    void runComputerAction({ action: "click", x, y }, `Clicked ${x}, ${y}`)
                  }
                  onTypeText={(text) =>
                    void runComputerAction({ action: "type", text }, "Typed text")
                  }
                  onPressKey={(key) =>
                    void runComputerAction({ action: "press", key }, `Pressed ${key}`)
                  }
                  onSelectArtifact={onSelectArtifact}
                  onUpdateArtifact={onUpdateArtifact}
                  onRemoveArtifact={onRemoveArtifact}
                  onSelectPath={(path, isDir) => {
                    if (isDir) {
                      setCurrentPath(path)
                    } else {
                      setSelectedFilePath(path)
                    }
                  }}
                  onClose={onClose}
                  onCreate={onCreate}
                />
              </Panel>
              <Separator className="h-px bg-border" />
              <Panel defaultSize={28} minSize={18}>
                <WorkspaceBottomPanel
                  activities={activities}
                  terminalUrl={session?.terminalUrl || null}
                />
              </Panel>
            </Group>
          </Panel>
          <Separator className="w-px bg-border" />
          <Panel defaultSize={20} minSize={14}>
            <WorkspaceRightPanel
              session={session}
              selectedFilePath={selectedFilePath}
              activities={activities}
            />
          </Panel>
        </Group>
      </div>
    </div>
  )
}

"use client"

import { useEffect, useMemo, useState } from "react"
import { ArtifactWorkspace } from "@/app/components/chat/artifact-canvas/artifact-workspace"
import { BrowserCanvas } from "@/app/components/chat/browser"
import type { CreateFormat } from "@/app/components/chat/document-editor"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { ScrollArea } from "@/components/ui/scroll-area"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { cn } from "@/lib/utils"
import { ArrowClockwise, ArrowSquareOut, Globe, Monitor, Terminal } from "@/lib/icons"
import type { Artifact } from "@/lib/artifact-store"
import { useBrowserStore, type BrowserProvider } from "@/lib/browser-store"
import type {
  DaytonaWorkspaceDrive,
  DaytonaWorkspaceFile,
  DaytonaWorkspaceSession,
} from "@/lib/daytona"
import type { WorkspaceActivity, WorkspaceTab } from "@/lib/workspace-store"
import { WorkspaceDriveControls } from "./workspace-drive-controls"

type WorkspaceMainPanelProps = {
  activeTab: WorkspaceTab
  artifacts: Artifact[]
  activeArtifactId?: string
  browserUrl: string
  desktopStatus: "idle" | "starting" | "ready" | "error"
  desktopScreenshot: string | null
  terminalUrl: string | null
  files: DaytonaWorkspaceFile[]
  selectedFilePath: string | null
  activities: WorkspaceActivity[]
  drive?: DaytonaWorkspaceDrive | null | undefined
  session: DaytonaWorkspaceSession | null
  onBrowserUrlChange: (url: string) => void
  onOpenBrowser: () => void
  onRefreshDesktop: () => void
  onStartDesktop: () => void
  onDesktopClick: (x: number, y: number) => void
  onTypeText: (text: string) => void
  onPressKey: (key: string) => void
  onSelectArtifact: (id: string) => void
  onUpdateArtifact: (id: string, content: string) => void
  onRemoveArtifact: (id: string) => void
  onSelectPath: (path: string, isDir: boolean) => void
  onNavigateUp?: () => void
  onRefreshFiles?: () => void
  onUploadFolder?: (files: File[], relativePaths: string[]) => void
  onSyncDrive?: (direction: "push" | "pull") => void
  onClose: () => void
  onCreate?: (format: CreateFormat, content: string) => void
}

const WORKSPACE_BROWSER_PROVIDERS = [
  {
    id: "agent-browser",
    label: "agent-browser",
    description: "Built-in browser automation",
  },
  {
    id: "browser-use",
    label: "browser-use",
    description: "Cloud browser automation",
  },
  {
    id: "daytona",
    label: "Daytona",
    description: "Workspace remote browser",
  },
] satisfies Array<{
  id: Extract<BrowserProvider, "agent-browser" | "browser-use" | "daytona">
  label: string
  description: string
}>

function DesktopPreview({
  screenshot,
  status,
  title,
  onRefresh,
  onStart,
  onImageClick,
}: {
  screenshot: string | null
  status: "idle" | "starting" | "ready" | "error"
  title: string
  onRefresh: () => void
  onStart: () => void
  onImageClick?: (x: number, y: number) => void
}) {
  return (
    <div className="flex h-full flex-col">
      <div className="flex items-center justify-between border-b px-4 py-2">
        <div className="flex items-center gap-2 text-sm font-medium">
          <Monitor className="size-4" />
          <span>{title}</span>
          <Badge variant="secondary">{status}</Badge>
        </div>
        <div className="flex items-center gap-2">
          <Button type="button" variant="ghost" size="sm" onClick={onRefresh}>
            <ArrowClockwise className="mr-2 size-4" />
            Refresh
          </Button>
          <Button type="button" size="sm" onClick={onStart}>
            Start
          </Button>
        </div>
      </div>

      <div className="flex flex-1 items-center justify-center bg-muted/20 p-6">
        {screenshot ? (
          <img
            src={`data:image/jpeg;base64,${screenshot}`}
            alt={title}
            className={cn(
              "max-h-full max-w-full rounded-lg border bg-background object-contain shadow-sm",
              onImageClick && "cursor-crosshair"
            )}
            onClick={(event) => {
              if (!onImageClick) return
              const rect = event.currentTarget.getBoundingClientRect()
              const scaleX = event.currentTarget.naturalWidth / rect.width
              const scaleY = event.currentTarget.naturalHeight / rect.height
              const x = Math.round((event.clientX - rect.left) * scaleX)
              const y = Math.round((event.clientY - rect.top) * scaleY)
              onImageClick(x, y)
            }}
          />
        ) : (
          <div className="text-muted-foreground rounded-xl border border-dashed bg-background px-6 py-8 text-sm">
            Start the remote desktop to capture the first screenshot.
          </div>
        )}
      </div>
    </div>
  )
}

export function WorkspaceMainPanel({
  activeTab,
  artifacts,
  activeArtifactId,
  browserUrl,
  desktopStatus,
  desktopScreenshot,
  terminalUrl,
  files,
  selectedFilePath,
  activities,
  drive,
  session,
  onBrowserUrlChange,
  onOpenBrowser,
  onRefreshDesktop,
  onStartDesktop,
  onDesktopClick,
  onTypeText,
  onPressKey,
  onSelectArtifact,
  onUpdateArtifact,
  onRemoveArtifact,
  onSelectPath,
  onNavigateUp,
  onRefreshFiles,
  onUploadFolder,
  onSyncDrive,
  onClose,
  onCreate,
}: WorkspaceMainPanelProps) {
  const [typeBuffer, setTypeBuffer] = useState("")
  const browserProvider = useBrowserStore((state) => state.browserProvider)
  const setBrowserProvider = useBrowserStore(
    (state) => state.setBrowserProvider
  )

  const workspaceBrowserProvider = WORKSPACE_BROWSER_PROVIDERS.some(
    (provider) => provider.id === browserProvider
  )
    ? browserProvider
    : "agent-browser"

  useEffect(() => {
    if (activeTab !== "browser") return
    if (workspaceBrowserProvider === browserProvider) return
    setBrowserProvider(workspaceBrowserProvider)
  }, [
    activeTab,
    browserProvider,
    setBrowserProvider,
    workspaceBrowserProvider,
  ])

  const selectedFile = useMemo(
    () => files.find((file) => file.path === selectedFilePath) || null,
    [files, selectedFilePath]
  )

  if (activeTab === "artifacts") {
    if (artifacts.length === 0) {
      return (
        <div className="flex h-full w-full items-center justify-center px-8 py-10">
          <div className="w-full text-center">
            <div className="text-muted-foreground text-sm font-medium">
              No artifacts yet
            </div>
            <div className="text-muted-foreground/70 mt-1 text-xs">
              Start from the conversation or switch tabs to use the rest of the
              workspace.
            </div>
          </div>
        </div>
      )
    }

    return (
      <ArtifactWorkspace
        artifacts={artifacts}
        activeId={activeArtifactId}
        onClose={onClose}
        onCreate={onCreate}
        onRemove={onRemoveArtifact}
        onSelect={onSelectArtifact}
        onUpdate={onUpdateArtifact}
      />
    )
  }

  if (activeTab === "terminal") {
    return terminalUrl ? (
      <iframe
        title="Workspace Terminal"
        src={terminalUrl}
        className="h-full w-full"
        sandbox="allow-same-origin allow-scripts allow-forms allow-popups"
      />
    ) : (
      <div className="text-muted-foreground flex h-full items-center justify-center">
        Terminal preview unavailable for this session.
      </div>
    )
  }

  if (activeTab === "files") {
    return (
      <div className="flex h-full flex-col">
        <div className="space-y-3 border-b px-4 py-3">
          <div className="flex items-start justify-between gap-3">
            <div>
              <div className="text-sm font-medium">Conversation Files</div>
              <div className="text-muted-foreground mt-1 text-xs">
                {session?.paths.conversationRoot || "No active path"}
              </div>
            </div>
            <div className="flex items-center gap-2">
              <Button
                type="button"
                variant="ghost"
                size="sm"
                onClick={onNavigateUp}
                disabled={!onNavigateUp}
              >
                Up
              </Button>
              <Button
                type="button"
                variant="ghost"
                size="sm"
                onClick={onRefreshFiles}
                disabled={!onRefreshFiles}
              >
                <ArrowClockwise className="mr-2 size-4" />
                Refresh
              </Button>
            </div>
          </div>
          {onUploadFolder && onSyncDrive ? (
            <WorkspaceDriveControls
              drive={drive}
              onUploadFolder={onUploadFolder}
              onSyncDrive={onSyncDrive}
            />
          ) : null}
        </div>
        <div className="grid flex-1 grid-cols-1 overflow-hidden lg:grid-cols-[minmax(0,1fr)_280px]">
          <ScrollArea className="border-r">
            <div className="space-y-1 p-3">
              {files.map((file) => (
                <button
                  key={file.path}
                  type="button"
                  className="hover:bg-accent flex w-full items-center justify-between rounded-md px-3 py-2 text-left text-sm transition"
                  onClick={() => onSelectPath(file.path, file.isDir)}
                >
                  <span className="truncate">{file.name}</span>
                  <Badge variant="outline">{file.isDir ? "dir" : "file"}</Badge>
                </button>
              ))}
            </div>
          </ScrollArea>
          <div className="space-y-2 p-4">
            <div className="text-sm font-medium">Selection</div>
            {selectedFile ? (
              <>
                <div className="text-xs">{selectedFile.name}</div>
                <div className="text-muted-foreground text-xs">
                  {selectedFile.path}
                </div>
                <div className="text-muted-foreground text-xs">
                  {selectedFile.size} bytes
                </div>
                <div className="text-muted-foreground text-xs">
                  {selectedFile.permissions}
                </div>
              </>
            ) : (
              <div className="text-muted-foreground text-xs">
                Pick a file or folder from the list.
              </div>
            )}
          </div>
        </div>
      </div>
    )
  }

  if (activeTab === "activity") {
    return (
      <ScrollArea className="h-full">
        <div className="space-y-3 p-4">
          {activities.map((activity) => (
            <div key={activity.id} className="rounded-xl border bg-background p-3">
              <div className="text-sm font-medium">{activity.title}</div>
              {activity.detail ? (
                <div className="text-muted-foreground mt-1 text-xs">
                  {activity.detail}
                </div>
              ) : null}
            </div>
          ))}
        </div>
      </ScrollArea>
    )
  }

  if (activeTab === "browser") {
    const isDaytonaBrowser = workspaceBrowserProvider === "daytona"

    return (
      <div className="flex h-full flex-col">
        <div className="flex items-center gap-2 border-b px-4 py-2">
          <Globe className="size-4 text-muted-foreground" />
          <Select
            value={workspaceBrowserProvider}
            onValueChange={(value) =>
              setBrowserProvider(value as BrowserProvider)
            }
          >
            <SelectTrigger
              className="h-9 w-[11.5rem] shrink-0 rounded-lg"
              aria-label="Browser provider"
            >
              <SelectValue placeholder="Provider" />
            </SelectTrigger>
            <SelectContent align="start">
              {WORKSPACE_BROWSER_PROVIDERS.map((provider) => (
                <SelectItem key={provider.id} value={provider.id}>
                  <div className="flex flex-col">
                    <span>{provider.label}</span>
                    <span className="text-muted-foreground text-xs">
                      {provider.description}
                    </span>
                  </div>
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          {isDaytonaBrowser ? (
            <>
              <Input
                value={browserUrl}
                onChange={(event) => onBrowserUrlChange(event.target.value)}
                placeholder="https://example.com"
              />
              <Button type="button" onClick={onOpenBrowser}>
                Open
              </Button>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                onClick={onRefreshDesktop}
              >
                <ArrowClockwise className="size-4" />
              </Button>
              {browserUrl ? (
                <Button asChild type="button" variant="ghost" size="icon">
                  <a href={browserUrl} target="_blank" rel="noreferrer">
                    <ArrowSquareOut className="size-4" />
                  </a>
                </Button>
              ) : null}
            </>
          ) : null}
        </div>

        {isDaytonaBrowser ? (
          <>
            <div className="border-b px-4 py-2">
              <div className="flex items-center gap-2">
                <Input
                  value={typeBuffer}
                  onChange={(event) => setTypeBuffer(event.target.value)}
                  placeholder="Type into the remote browser"
                />
                <Button
                  type="button"
                  variant="secondary"
                  onClick={() => {
                    if (!typeBuffer.trim()) return
                    onTypeText(typeBuffer)
                    setTypeBuffer("")
                  }}
                >
                  Type
                </Button>
                <Button
                  type="button"
                  variant="ghost"
                  onClick={() => onPressKey("Return")}
                >
                  Enter
                </Button>
              </div>
            </div>

            <DesktopPreview
              screenshot={desktopScreenshot}
              status={desktopStatus}
              title="Remote Browser"
              onRefresh={onRefreshDesktop}
              onStart={onOpenBrowser}
              onImageClick={onDesktopClick}
            />
          </>
        ) : (
          <div className="min-h-0 flex-1 overflow-hidden">
            <BrowserCanvas className="h-full" />
          </div>
        )}
      </div>
    )
  }

  return (
    <DesktopPreview
      screenshot={desktopScreenshot}
      status={desktopStatus}
      title="Remote Desktop"
      onRefresh={onRefreshDesktop}
      onStart={onStartDesktop}
      onImageClick={onDesktopClick}
    />
  )
}

