"use client"

import {
  buildPreviewContent,
  CodeBlock,
  CodeBlockCode,
} from "@/components/prompt-kit/code-block"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import type { Artifact } from "@/lib/artifact-store"
import { downloadAsHtml, printAsPdf } from "@/lib/download"
import {
  ArrowSquareOut,
  Check,
  Code,
  Copy,
  DownloadSimple,
  Eye,
  FileHtml,
  FilePdf,
  FileText,
  Pencil,
  Trash,
  X,
} from "@/lib/icons"
import { cn } from "@/lib/utils"
import { useCallback, useEffect, useMemo, useRef, useState } from "react"
import { ArtifactEditor } from "../artifact-editor"
import { BrowserCanvas } from "../browser"
import type { CreateFormat } from "../document-editor"
import { DocumentEditor } from "../document-editor"
import { MediaViewer } from "../media-viewer"
import {
  parseSlidesFromContent,
  PresentationViewer,
} from "../presentation-viewer"

type ArtifactMode =
  | "preview"
  | "code"
  | "edit"
  | "document"
  | "presentation"
  | "media"

type ArtifactWorkspaceProps = {
  artifacts: Artifact[]
  activeId?: string
  onClose: () => void
  onCreate?: (format: CreateFormat, content: string) => void
  onRemove: (id: string) => void
  onSelect: (id: string) => void
  onUpdate: (id: string, content: string) => void
  isMobile?: boolean
}

function getArtifactLanguage(type: Artifact["type"]) {
  switch (type) {
    case "svg":
      return "svg"
    case "html":
      return "html"
    case "mermaid":
      return "mermaid"
    case "json":
      return "json"
    case "csv":
      return "csv"
    default:
      return "code"
  }
}

function getArtifactDownloadExtension(type: Artifact["type"]) {
  switch (type) {
    case "html":
    case "document":
      return "html"
    case "svg":
      return "svg"
    case "code":
      return "tsx"
    default:
      return "txt"
  }
}

function getDefaultMode(
  activeArtifact?: Artifact,
  hasPreview?: boolean
): ArtifactMode {
  if (!activeArtifact) return "preview"

  if (
    activeArtifact.type === "document" ||
    activeArtifact.type === "text" ||
    activeArtifact.type === "mermaid"
  ) {
    return "document"
  }

  if (activeArtifact.type === "presentation") {
    return "presentation"
  }

  if (activeArtifact.type === "image" || activeArtifact.type === "video") {
    return "media"
  }

  return hasPreview ? "preview" : "code"
}

export function ArtifactWorkspace({
  artifacts,
  activeId,
  onClose,
  onCreate,
  onRemove,
  onSelect,
  onUpdate,
  isMobile = false,
}: ArtifactWorkspaceProps) {
  const [mode, setMode] = useState<ArtifactMode>("preview")
  const [copied, setCopied] = useState(false)
  const copyResetTimeout = useRef<ReturnType<typeof setTimeout> | null>(null)
  const activeValue = activeId ?? artifacts[0]?.id
  const activeArtifact =
    artifacts.find((artifact) => artifact.id === activeValue) || artifacts[0]

  const previewContent = useMemo(() => {
    if (!activeArtifact) return null

    if (
      activeArtifact.type === "document" ||
      activeArtifact.type === "text" ||
      activeArtifact.type === "presentation"
    ) {
      return null
    }

    return buildPreviewContent(
      getArtifactLanguage(activeArtifact.type),
      activeArtifact.content,
      true,
      true
    )
  }, [activeArtifact])

  const hasPreview = Boolean(previewContent)
  const defaultMode = getDefaultMode(activeArtifact, hasPreview)

  const parsedSlidesMap = useMemo(() => {
    const map = new Map<string, ReturnType<typeof parseSlidesFromContent>>()

    for (const artifact of artifacts) {
      if (artifact.type === "presentation") {
        map.set(artifact.id, parseSlidesFromContent(artifact.content))
      }
    }

    return map
  }, [artifacts])

  useEffect(() => {
    setMode(defaultMode)
  }, [activeValue, defaultMode])

  useEffect(() => {
    setCopied(false)
    if (!copyResetTimeout.current) return

    clearTimeout(copyResetTimeout.current)
    copyResetTimeout.current = null
  }, [activeArtifact?.id])

  useEffect(() => {
    return () => {
      if (copyResetTimeout.current) {
        clearTimeout(copyResetTimeout.current)
      }
    }
  }, [])

  const handleCopyActiveArtifact = useCallback(async () => {
    if (!activeArtifact?.content) return
    if (typeof navigator === "undefined" || !navigator.clipboard) return

    try {
      await navigator.clipboard.writeText(activeArtifact.content)
      setCopied(true)

      if (copyResetTimeout.current) {
        clearTimeout(copyResetTimeout.current)
      }

      copyResetTimeout.current = setTimeout(() => {
        setCopied(false)
        copyResetTimeout.current = null
      }, 1000)
    } catch (error) {
      console.error("Failed to copy artifact content", error)
    }
  }, [activeArtifact?.content])

  const handleDownloadArtifact = useCallback(() => {
    if (!activeArtifact?.content) return

    const filename = `${activeArtifact.title || "artifact"}.${getArtifactDownloadExtension(activeArtifact.type)}`
    downloadAsHtml(activeArtifact.content, filename, "text/plain")
  }, [activeArtifact])

  const handleDownloadPDF = useCallback(() => {
    if (!activeArtifact?.content) return
    printAsPdf(activeArtifact.content, activeArtifact.title || "Document")
  }, [activeArtifact])

  return (
    <Tabs
      value={activeValue}
      onValueChange={onSelect}
      className="flex h-full flex-1 flex-col overflow-hidden"
    >
      <div className="bg-background flex flex-1 flex-col overflow-hidden">
        <div className="border-b px-4 py-3">
          <div
            className={cn(
              "flex gap-3",
              isMobile ? "flex-col" : "items-start justify-between"
            )}
          >
            <div className="min-w-0 flex-1">
              <ScrollArea className="w-full whitespace-nowrap">
                <TabsList className="h-auto w-max min-w-full justify-start gap-1 rounded-none bg-transparent p-0">
                  {artifacts.map((artifact) => (
                    <TabsTrigger
                      key={artifact.id}
                      value={artifact.id}
                      className="border-border data-[state=active]:bg-accent data-[state=active]:text-foreground h-8 rounded-full border px-3 text-xs"
                    >
                      {artifact.title}
                    </TabsTrigger>
                  ))}
                </TabsList>
              </ScrollArea>
            </div>

            <div
              className={cn(
                "flex shrink-0 items-center gap-2",
                isMobile && "justify-between"
              )}
            >
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8"
                    aria-label="Download options"
                    disabled={!activeArtifact?.content}
                  >
                    <DownloadSimple className="size-4" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="start" className="w-44">
                  <DropdownMenuItem
                    onClick={handleDownloadArtifact}
                    className="gap-2"
                  >
                    <FileHtml className="size-4" />
                    <span>Download HTML</span>
                  </DropdownMenuItem>
                  <DropdownMenuItem
                    onClick={handleDownloadPDF}
                    className="gap-2"
                  >
                    <FilePdf className="size-4" />
                    <span>Save as PDF</span>
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>

              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8"
                onClick={() => activeArtifact && onRemove(activeArtifact.id)}
                aria-label="Remove artifact"
                disabled={!activeArtifact}
              >
                <Trash className="size-4" />
              </Button>

              <div className="bg-muted/50 flex items-center rounded-lg border p-0.5">
                {defaultMode === "document" ? (
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setMode("document")}
                    className={cn(
                      "h-7 w-7",
                      mode === "document" && "bg-background shadow-sm"
                    )}
                    aria-label="Document Editor"
                  >
                    <FileText className="size-3.5" />
                  </Button>
                ) : null}
                {hasPreview ? (
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setMode("preview")}
                    className={cn(
                      "h-7 w-7",
                      mode === "preview" && "bg-background shadow-sm"
                    )}
                    aria-label="Preview"
                  >
                    <Eye className="size-3.5" />
                  </Button>
                ) : null}
                <Button
                  variant="ghost"
                  size="icon"
                  onClick={() => setMode("code")}
                  className={cn(
                    "h-7 w-7",
                    mode === "code" && "bg-background shadow-sm"
                  )}
                  aria-label="Code"
                >
                  <Code className="size-3.5" />
                </Button>
                <Button
                  variant="ghost"
                  size="icon"
                  onClick={() => setMode("edit")}
                  className={cn(
                    "h-7 w-7",
                    mode === "edit" && "bg-background shadow-sm"
                  )}
                  aria-label="Edit"
                >
                  <Pencil className="size-3.5" />
                </Button>
              </div>

              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8"
                onClick={handleCopyActiveArtifact}
                aria-label={copied ? "Copied" : "Copy artifact"}
                disabled={!activeArtifact?.content}
              >
                {copied ? (
                  <Check className="size-4" />
                ) : (
                  <Copy className="size-4" />
                )}
              </Button>

              {mode === "preview" && previewContent?.supportsExternal ? (
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8"
                  onClick={previewContent.onOpenExternal}
                  aria-label="Open in new tab"
                >
                  <ArrowSquareOut className="size-4" />
                </Button>
              ) : null}

              <Button
                variant="ghost"
                size="icon"
                className="h-8 w-8"
                onClick={onClose}
                aria-label="Close artifact view"
              >
                <X className="size-4" />
              </Button>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-hidden">
          {artifacts.map((artifact) => (
            <TabsContent
              key={artifact.id}
              value={artifact.id}
              className="mt-0 h-full flex-col data-[state=active]:flex"
            >
              {artifact.type === "browser" ? (
                <div className="h-full overflow-hidden">
                  <BrowserCanvas className="h-full" />
                </div>
              ) : mode === "document" ? (
                <DocumentEditor
                  content={artifact.content}
                  onChange={(content) => onUpdate(artifact.id, content)}
                  onCreate={onCreate}
                  placeholder="Start writing or edit the document..."
                />
              ) : mode === "presentation" ? (
                <PresentationViewer
                  slides={parsedSlidesMap.get(artifact.id) || []}
                  title={artifact.title}
                  theme="modern"
                />
              ) : mode === "media" ? (
                <MediaViewer
                  type={artifact.type as "image" | "video"}
                  url={artifact.content}
                  title={artifact.title}
                />
              ) : mode === "edit" ? (
                <ArtifactEditor
                  artifact={artifact}
                  onSave={(content) => {
                    onUpdate(artifact.id, content)
                    setMode(defaultMode)
                  }}
                  onCancel={() => setMode(defaultMode)}
                />
              ) : mode === "preview" ? (
                <ArtifactPreviewRenderer artifact={artifact} />
              ) : (
                <div className="h-full overflow-auto p-4">
                  <CodeBlock className="border-none bg-transparent p-0">
                    <CodeBlockCode
                      code={artifact.content}
                      language={
                        artifact.type === "svg"
                          ? "xml"
                          : artifact.type === "html"
                            ? "html"
                            : "tsx"
                      }
                    />
                  </CodeBlock>
                </div>
              )}
            </TabsContent>
          ))}
        </div>
      </div>
    </Tabs>
  )
}

function ArtifactPreviewRenderer({ artifact }: { artifact: Artifact }) {
  const previewContent = useMemo(
    () =>
      buildPreviewContent(
        getArtifactLanguage(artifact.type),
        artifact.content,
        true,
        true
      ),
    [artifact]
  )

  if (!previewContent) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <p className="text-muted-foreground">No preview available.</p>
      </div>
    )
  }

  return (
    <div className="h-full w-full overflow-hidden">{previewContent.node}</div>
  )
}

