  { value: "files", label: "Files", icon: <FolderTree className="h-3.5 w-3.5" /> },
  { value: "agent-output", label: "Agent", icon: <Bot className="h-3.5 w-3.5" /> },
];

export default function WorkspacePanel() {
  const { isOpen, activeTab, setActiveTab } = useWorkspaceStore();

  if (!isOpen) return null;

  return (
    <div className="h-full flex flex-col bg-background border-l">
      <Tabs
        value={activeTab}
        onValueChange={(v) => setActiveTab(v as WorkspaceTab)}
        className="flex flex-col h-full"
      >
        <div className="border-b px-2 pt-2">
          <TabsList className="h-8 w-full justify-start gap-0.5 bg-transparent p-0">
            {TABS.map((tab) => (
              <TabsTrigger
                key={tab.value}
                value={tab.value}
                className="h-7 px-2 text-xs gap-1 data-[state=active]:bg-muted"
              >
                {tab.icon}
                <span className="hidden xl:inline">{tab.label}</span>
              </TabsTrigger>
            ))}
          </TabsList>
        </div>

        <ScrollArea className="flex-1">
          <div className="p-3">
            {activeTab === "artifacts" && <ArtifactSurface />}
            {activeTab === "browser" && <BrowserSurface />}
            {activeTab === "document" && <DocumentSurface />}
            {activeTab === "terminal" && <TerminalSurface />}
            {activeTab === "files" && <FilesSurface />}
            {activeTab === "agent-output" && <AgentOutputSurface />}
          </div>
        </ScrollArea>
      </Tabs>
    </div>
  );
}

"use client";

import { useWorkspaceStore, type ArtifactType } from "../workspace-store";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Button } from "@/components/ui/button";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { X, Copy, Code2, FileCode, Image, GitCompare, Braces } from "lucide-react";
import ReactMarkdown from "react-markdown";

const ARTIFACT_ICONS: Record<ArtifactType, React.ReactNode> = {
  code: <Code2 className="h-4 w-4" />,
  html: <FileCode className="h-4 w-4" />,
  svg: <Image className="h-4 w-4" />,
  react: <Braces className="h-4 w-4" />,
  image: <Image className="h-4 w-4" />,
  diff: <GitCompare className="h-4 w-4" />,
  mermaid: <Code2 className="h-4 w-4" />,
};

function ArtifactViewer() {
  const { artifacts, activeArtifactId, setActiveArtifact, removeArtifact, updateArtifact } =
    useWorkspaceStore();

  const active = artifacts.find((a) => a.id === activeArtifactId);

  if (artifacts.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
        <Code2 className="h-8 w-8 mb-2" />
        <p className="text-sm">No artifacts yet</p>
        <p className="text-xs">Ask Dexter to create something</p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {/* Artifact list */}
      <div className="flex gap-1 flex-wrap">
        {artifacts.map((a) => (
          <Button
            key={a.id}
            variant={a.id === activeArtifactId ? "default" : "outline"}
            size="sm"
            className="h-7 text-xs gap-1"
            onClick={() => setActiveArtifact(a.id)}
          >
            {ARTIFACT_ICONS[a.type]}
            {a.title}
            <span
              className="ml-1 hover:bg-destructive/20 rounded p-0.5"
              onClick={(e) => {
                e.stopPropagation();
                removeArtifact(a.id);
              }}
            >
              <X className="h-3 w-3" />
            </span>
          </Button>
        ))}
      </div>

      {/* Active artifact content */}
      {active && (
        <div className="border rounded-lg overflow-hidden">
          <div className="flex items-center justify-between bg-muted/50 px-3 py-1.5 border-b">
            <span className="text-xs font-medium">{active.title}</span>
            <Button
              variant="ghost"
              size="sm"
              className="h-6 w-6 p-0"
              onClick={() => navigator.clipboard.writeText(active.content)}
            >
              <Copy className="h-3 w-3" />
            </Button>
          </div>
          <ScrollArea className="max-h-[60vh]">
            <div className="p-3">
              {active.type === "html" || active.type === "svg" ? (
                <div
                  className="prose prose-sm max-w-none dark:prose-invert"
                  dangerouslySetInnerHTML={{ __html: active.content }}
                />
              ) : active.type === "mermaid" ? (
                <pre className="text-xs font-mono bg-muted/30 p-3 rounded overflow-x-auto">
                  {active.content}
                </pre>
              ) : active.type === "image" ? (
                <img
                  src={active.content}
                  alt={active.title}
                  className="max-w-full rounded"
                />
              ) : (
                <pre className="text-xs font-mono bg-muted/30 p-3 rounded overflow-x-auto whitespace-pre-wrap">
                  {active.content}
                </pre>
              )}
            </div>
          </ScrollArea>
        </div>
      )}
    </div>
  );
}

export default function ArtifactSurface() {
  return <ArtifactViewer />;
}

"use client";

import { useWorkspaceStore } from "../workspace-store";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Globe, RefreshCw, ExternalLink, Loader2 } from "lucide-react";

export default function BrowserSurface() {
  const {
    browserUrl,
    browserStatus,
    browserScreenshot,
    setBrowserUrl,
    setBrowserStatus,
    setBrowserScreenshot,
  } = useWorkspaceStore();

  const handleNavigate = (url: string) => {
    if (!url.startsWith("http")) url = "https://" + url;
    setBrowserUrl(url);
    setBrowserStatus("loading");
    // The agent's browse_web tool will set screenshot/status via CopilotKit action
  };

  return (
    <div className="space-y-3">
      {/* URL bar */}
      <div className="flex gap-2">
        <div className="relative flex-1">
          <Globe className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
          <Input
            value={browserUrl === "about:blank" ? "" : browserUrl}
            placeholder="Enter URL..."
            className="h-8 pl-8 text-xs"
            onKeyDown={(e) => {
              if (e.key === "Enter") {
                handleNavigate((e.target as HTMLInputElement).value);
              }
            }}
            onChange={(e) => setBrowserUrl(e.target.value)}
          />
        </div>
        <Button
          variant="outline"
          size="sm"
          className="h-8"
          onClick={() => handleNavigate(browserUrl)}
          disabled={browserStatus === "loading"}
        >
          {browserStatus === "loading" ? (
            <Loader2 className="h-3.5 w-3.5 animate-spin" />
          ) : (
            <RefreshCw className="h-3.5 w-3.5" />
          )}
        </Button>
      </div>

      {/* Browser viewport */}
      <div className="border rounded-lg overflow-hidden bg-muted/10 aspect-video flex items-center justify-center">
        {browserStatus === "loading" ? (
          <div className="flex flex-col items-center text-muted-foreground">
            <Loader2 className="h-6 w-6 animate-spin mb-2" />
            <p className="text-xs">Loading...</p>
          </div>
        ) : browserScreenshot ? (
          <img
            src={`data:image/png;base64,${browserScreenshot}`}
            alt="Browser screenshot"
            className="w-full h-full object-contain"
          />
        ) : (
          <div className="flex flex-col items-center text-muted-foreground">
            <Globe className="h-8 w-8 mb-2" />
            <p className="text-sm">No page loaded</p>
            <p className="text-xs">Ask Dexter to browse a URL</p>
          </div>
        )}
      </div>

      {/* Open external link */}
      {browserUrl && browserUrl !== "about:blank" && (
        <Button
          variant="ghost"
          size="sm"
          className="w-full text-xs"
          onClick={() => window.open(browserUrl, "_blank")}
        >
          <ExternalLink className="h-3 w-3 mr-1" />
          Open in browser
        </Button>
      )}
    </div>
  );
}

"use client";

import { useWorkspaceStore } from "../workspace-store";
import { useEffect, useRef } from "react";
import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Bold, Italic, List, Heading2, Save, FileText } from "lucide-react";

export default function DocumentSurface() {
  const {
    documentContent,
    documentTitle,
    setDocumentContent,
    setDocumentTitle,
  } = useWorkspaceStore();

  const editor = useEditor({
    extensions: [StarterKit],
    content: documentContent,
    onUpdate: ({ editor }) => {
      setDocumentContent(editor.getHTML());
    },
    editorProps: {
      attributes: {
        class: "prose prose-sm dark:prose-invert max-w-none focus:outline-none min-h-[200px] p-3",
      },
    },
  });

  // Sync content from store (when agent sets it)
  const prevContent = useRef(documentContent);
  useEffect(() => {
    if (documentContent !== prevContent.current && editor) {
      const currentEditorHTML = editor.getHTML();
      if (documentContent !== currentEditorHTML) {
        editor.commands.setContent(documentContent);
      }
      prevContent.current = documentContent;
    }
  }, [documentContent, editor]);

  return (
    <div className="space-y-3">
      {/* Title */}
      <Input
        value={documentTitle}
        onChange={(e) => setDocumentTitle(e.target.value)}
        className="h-8 text-sm font-medium"
        placeholder="Document title..."
      />

      {/* Toolbar */}
      <div className="flex gap-1 border rounded-lg p-1 bg-muted/30">
        <Button
          variant="ghost"
          size="sm"
          className="h-7 w-7 p-0"
          onClick={() => editor?.chain().focus().toggleBold().run()}
        >
          <Bold className="h-3.5 w-3.5" />
        </Button>
        <Button
          variant="ghost"
          size="sm"
          className="h-7 w-7 p-0"
          onClick={() => editor?.chain().focus().toggleItalic().run()}
        >
          <Italic className="h-3.5 w-3.5" />
        </Button>
        <Button
          variant="ghost"
          size="sm"
          className="h-7 w-7 p-0"
          onClick={() => editor?.chain().focus().toggleHeading({ level: 2 }).run()}
        >
          <Heading2 className="h-3.5 w-3.5" />
        </Button>
        <Button
          variant="ghost"
          size="sm"
          className="h-7 w-7 p-0"
          onClick={() => editor?.chain().focus().toggleBulletList().run()}
        >
          <List className="h-3.5 w-3.5" />
        </Button>
      </div>

      {/* Editor */}
      <div className="border rounded-lg min-h-[200px]">
        <EditorContent editor={editor} />
      </div>

      {!documentContent && (
        <div className="flex items-center justify-center py-8 text-muted-foreground">
          <div className="text-center">
            <FileText className="h-8 w-8 mx-auto mb-2" />
            <p className="text-sm">Empty document</p>
            <p className="text-xs">Start typing or ask Dexter to write</p>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useWorkspaceStore } from "../workspace-store";
import { useEffect, useRef } from "react";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Terminal as TerminalIcon, Trash2, Copy } from "lucide-react";

export default function TerminalSurface() {
  const { terminalOutput, appendTerminalOutput, terminalSessionId } =
    useWorkspaceStore();
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on new output
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [terminalOutput]);

  const handleCopy = () => {
    navigator.clipboard.writeText(terminalOutput);
  };

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <TerminalIcon className="h-4 w-4 text-muted-foreground" />
          <span className="text-xs text-muted-foreground">
            {terminalSessionId ? `Session: ${terminalSessionId.slice(0, 8)}` : "No active session"}
          </span>
        </div>
        <div className="flex gap-1">
          <Button
            variant="ghost"
            size="sm"
            className="h-6 w-6 p-0"
            onClick={handleCopy}
            disabled={!terminalOutput}
          >
            <Copy className="h-3 w-3" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="h-6 w-6 p-0"
            onClick={() => useWorkspaceStore.setState({ terminalOutput: "" })}
            disabled={!terminalOutput}
          >
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Terminal output */}
      <div
        ref={scrollRef}
        className="bg-zinc-950 text-green-400 font-mono text-xs rounded-lg p-3 min-h-[200px] max-h-[60vh] overflow-y-auto whitespace-pre-wrap"
      >
        {terminalOutput || (
          <span className="text-zinc-500">
            Terminal output will appear here when Dexter executes code...
          </span>
        )}
      </div>
    </div>
  );
}

"use client";

import { useWorkspaceStore, type WorkspaceFile } from "../workspace-store";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  FolderTree,
  File,
  Folder,
  ChevronRight,
  ArrowUp,
} from "lucide-react";

export default function FilesSurface() {
  const { files, currentPath, selectedFilePath, setCurrentPath, setSelectedFilePath } =
    useWorkspaceStore();

  const directories = files.filter((f) => f.isDir);
  const regularFiles = files.filter((f) => !f.isDir);
  const sorted = [...directories, ...regularFiles];

  const handleNavigate = (file: WorkspaceFile) => {
    if (file.isDir) {
      setCurrentPath(file.path);
      // The agent's list_files tool will populate via CopilotKit action
    } else {
      setSelectedFilePath(file.path);
      // The agent's read_file tool will populate content via CopilotKit action
    }
  };

  return (
    <div className="space-y-3">
      {/* Breadcrumb */}
      <div className="flex items-center gap-1 text-xs text-muted-foreground">
        <Button
          variant="ghost"
          size="sm"
          className="h-6 w-6 p-0"
          onClick={() => setCurrentPath(null)}
        >
          <ArrowUp className="h-3 w-3" />
        </Button>
        <span className="font-mono truncate">
          {currentPath || "/"}
        </span>
      </div>

      {/* File list */}
      {sorted.length > 0 ? (
        <div className="border rounded-lg divide-y">
          {sorted.map((file) => (
            <Button
              key={file.path}
              variant="ghost"
              size="sm"
              className={`w-full h-8 justify-start px-3 text-xs font-normal ${
                selectedFilePath === file.path ? "bg-muted" : ""
              }`}
              onClick={() => handleNavigate(file)}
            >
              {file.isDir ? (
                <Folder className="h-3.5 w-3.5 mr-2 text-blue-400" />
              ) : (
                <File className="h-3.5 w-3.5 mr-2 text-muted-foreground" />
              )}
              <span className="truncate">{file.name}</span>
              {!file.isDir && (
                <span className="ml-auto text-muted-foreground">
                  {formatSize(file.size)}
                </span>
              )}
              {file.isDir && <ChevronRight className="h-3 w-3 ml-auto" />}
            </Button>
          ))}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
          <FolderTree className="h-8 w-8 mb-2" />
          <p className="text-sm">No files loaded</p>
          <p className="text-xs">Ask Dexter to explore a directory</p>
        </div>
      )}
    </div>
  );
}

function formatSize(bytes: number): string {
  if (bytes === 0) return "0 B";
  const k = 1024;
  const sizes = ["B", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + " " + sizes[i];
}

"use client";

import { useWorkspaceStore } from "../workspace-store";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Button } from "@/components/ui/button";
import { Bot, Trash2, Copy } from "lucide-react";
import ReactMarkdown from "react-markdown";

export default function AgentOutputSurface() {
  const { agentOutputStream, agentOutputMetadata, clearAgentOutput } =
    useWorkspaceStore();

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Bot className="h-4 w-4 text-primary" />
          <span className="text-xs text-muted-foreground">Agent output stream</span>
        </div>
        <div className="flex gap-1">
          <Button
            variant="ghost"
            size="sm"
            className="h-6 w-6 p-0"
            onClick={() => navigator.clipboard.writeText(agentOutputStream)}
            disabled={!agentOutputStream}
          >
            <Copy className="h-3 w-3" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="h-6 w-6 p-0"
            onClick={clearAgentOutput}
            disabled={!agentOutputStream}
          >
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Output stream */}
      {agentOutputStream ? (
        <div className="border rounded-lg p-3 bg-muted/10">
          <div className="prose prose-sm dark:prose-invert max-w-none text-xs">
            <ReactMarkdown>{agentOutputStream}</ReactMarkdown>
          </div>
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
          <Bot className="h-8 w-8 mb-2" />
          <p className="text-sm">No agent output</p>
          <p className="text-xs">Agent activity will stream here</p>
        </div>
      )}

      {/* Metadata display */}
      {Object.keys(agentOutputMetadata).length > 0 && (
        <details className="text-xs">
          <summary className="cursor-pointer text-muted-foreground hover:text-foreground">
            Metadata
          </summary>
          <pre className="mt-1 bg-muted/30 rounded p-2 font-mono text-[10px] overflow-x-auto">
            {JSON.stringify(agentOutputMetadata, null, 2)}
          </pre>
        </details>
      )}
    </div>
  );
}

