    description: "Creates a new artifact to display in the user's workspace.",
    parameters: [
      {
        name: "type",
        type: "string",
        description:
          "The type of artifact ('code', 'html', 'svg', 'react', 'image', 'diff', 'mermaid').",
      },
      {
        name: "title",
        type: "string",
