      setFiles(files);
      setActiveTab("files");
      pushActivity({
        kind: "info",
        title: `Listed files in ${path || "/"}`,
      });
      return `Successfully listed files.`;
    },
  });

  useCopilotAction({
    name: "read_file",
    description: "Reads the contents of a file.",
    parameters: [
      {
        name: "path",
        type: "string",
        description: "The path of the file to read.",
      },
      {
        name: "content",
        type: "string",
        description: "The content of the file.",
      },
