          {isOpen && (
            <>
              <PanelResizeHandle className="w-1 bg-border cursor-col-resize hover:bg-primary/50 transition-colors" />
              <Panel
                defaultSize={35}
                minSize={20}
                onResize={setPanelSize}
              >
                <WorkspacePanel />
              </Panel>
            </>
          )}
        </PanelGroup>
      </div>
    </div>
  );
}

