    u, v = edge
    cu = node_to_comm.get(u, set())
    cv = node_to_comm.get(v, set())
    if cu and cv and cu != cv:
        bridges.append((cu, cv, u, v))

# Deduplicate bridge communities
bridge_comms = {}
for cu, cv, u, v in bridges:
    cu_s = sorted(cu)[0] if cu else -1
    cv_s = sorted(cv)[0] if cv else -1
    key = (min(cu_s, cv_s), max(cu_s, cv_s))
