"use client";

import { useState, useRef, useEffect, type FormEvent } from "react";
import { useWorkspaceTools } from "@/components/copilot/frontend-tools";
import { sendChatMessage } from "@/lib/copilot/chat-adapter";

interface ChatMessage {
  id: string;
  role: "user" | "assistant";
  content: string;
}

const WELCOME_MESSAGE: ChatMessage = {
  id: "welcome",
  role: "assistant",
  content: "Hello! I'm Dexter, your AI workspace assistant. How can I help you today?",
};

export default function ChatPage() {
  // Register CopilotKit workspace actions (required for agent tool outputs)
  useWorkspaceTools();

  const [messages, setMessages] = useState<ChatMessage[]>([WELCOME_MESSAGE]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    const text = input.trim();
    if (!text || isLoading) return;

    const userMsg: ChatMessage = { id: crypto.randomUUID(), role: "user", content: text };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsLoading(true);

    try {
      const reply = await sendChatMessage(text);
      setMessages((prev) => [...prev, { id: crypto.randomUUID(), role: "assistant", content: reply }]);
    } catch {
      setMessages((prev) => [
        ...prev,
        { id: crypto.randomUUID(), role: "assistant", content: "Sorry, something went wrong. Is the agent service running?" },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-full flex flex-col">
      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
          >
            <div
              className={`max-w-[80%] rounded-lg px-4 py-2 ${
                msg.role === "user"
                  ? "bg-primary text-primary-foreground"
                  : "bg-muted text-muted-foreground"
              }`}
            >
              <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-muted rounded-lg px-4 py-2">
              <p className="text-sm text-muted-foreground animate-pulse">Thinking...</p>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <form onSubmit={handleSubmit} className="border-t p-4 flex gap-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Message Dexter..."
          className="flex-1 border rounded-lg px-4 py-2 text-sm bg-background focus:outline-none focus:ring-2 focus:ring-primary/50"
          disabled={isLoading}
        />
        <button
          type="submit"
          disabled={!input.trim() || isLoading}
          className="px-4 py-2 bg-primary text-primary-foreground rounded-lg text-sm font-medium disabled:opacity-50 hover:bg-primary/90"
        >
          Send
        </button>
      </form>
    </div>
  );
}

/**
 * Chat adapter — sends messages to the Python LangGraph agent service.
 * Falls back to a local echo when the agent isn't running.
 */

const AGENT_URL = (process.env.NEXT_PUBLIC_AGENT_SERVICE_URL || "http://localhost:8000") + "/api/agent";

export async function sendChatMessage(message: string): Promise<string> {
  try {
    const response = await fetch(AGENT_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        messages: [{ role: "user", content: message }],
      }),
      signal: AbortSignal.timeout(10000),
    });

    if (!response.ok) {
      throw new Error(`Agent returned ${response.status}`);
    }

    // Handle streaming or plain JSON response
    const contentType = response.headers.get("content-type") || "";
    if (contentType.includes("text/event-stream")) {
      const text = await response.text();
      // Extract content from SSE stream
      const content = text
        .split("\n")
        .filter((line) => line.startsWith("data: "))
        .map((line) => {
          try {
            const parsed = JSON.parse(line.slice(6));
            return parsed.content || parsed.text || "";
          } catch {
            return "";
          }
        })
        .join("");
      return content || "Agent returned an empty response.";
    }

    const data = await response.json();
    return data.content || data.response || data.message || "Done.";
  } catch (error) {
    if (error instanceof TypeError && error.message.includes("fetch")) {
      // Agent service not running — use local echo
      return `[Local fallback] The agent service isn't running yet. You said: "${message}"\n\nStart the agent with:\n\`\`\`\ncd services/agent && source .venv/bin/activate && uvicorn app.main:app --port 8000 --reload\n\`\`\`\n\nOnce running, messages will flow through the LangGraph backend.`;
    }
    throw error;
  }
}

